const item = $input.first();
const description = item.json.description ?? '';
const binary = item.binary ?? {};

const imageKeys = Object.keys(binary)
  .filter(k => k === 'images' || k.startsWith('images_'))
  .sort();

if (imageKeys.length === 0) {
  throw new Error('No images found in form submission.');
}

return imageKeys.map(key => ({
  json: { description },
  binary: { image: binary[key] }
}));

const allItems = $input.item.json.data;
const images = allItems.map(item => item.imageBase64);
const description = $("On form submission").item.json.description ?? '';
return { json: { images, description } };
